-- Luke Chapter 18
-- Theme: Persistent Prayer, Humble Faith, and the Cost of Entry into the Kingdom
-- 43 verses

INSERT INTO chapters (book_id, chapter_number, overview, theme, key_word_original, key_word_meaning, outline)
SELECT b.id, 18,
  'Luke 18 opens with two parables on prayer that bracket a sharp contrast between presumptuous and humble approaches to God (vv.1-14). The parable of the Persistent Widow (vv.1-8) teaches that God''s elect must pray persistently and not lose heart, with the implied argument from lesser to greater: if an unjust judge yields to persistent request, how much more will the just God answer his own? The parable of the Pharisee and the Tax Collector (vv.9-14) then exposes the theological catastrophe of self-righteous prayer versus the saving power of humble confession.' ||
  'The central section (vv.15-30) brings together three interconnected episodes on the conditions of kingdom entry: children as the paradigm of receptive faith (vv.15-17), the rich young ruler whose attachment to wealth reveals the idol beneath his religious compliance (vv.18-25), and the disciples'' bewilderment — answered by Jesus''s declaration that what is impossible for humans is possible for God and rewarded by his promise of hundredfold return to those who have genuinely left all (vv.26-30). These three episodes form a progressive exploration of what it means to "receive the kingdom of God as a little child" (v.17).' ||
  'The third passion prediction (vv.31-34) is the most detailed in Luke''s Gospel, explicitly naming the Gentiles, the mocking, the spitting, the scourging, and the resurrection on the third day. Yet Luke adds a remarkable editorial note: "they understood none of these things: and this saying was hid from them, neither knew they the things which were spoken" (v.34). The disciples'' incomprehension is not intellectual failure but divine veiling — God purposefully withholds understanding until resurrection light makes the cross interpretable.' ||
  'The chapter concludes with the healing of Blind Bartimaeus (vv.35-43; cf. Mark 10:46-52), who is identified only as "a certain blind man" in Luke''s account. His persistent cry — "Jesus, thou Son of David, have mercy on me" (v.38) — echoes the widow''s persistence, the tax collector''s humble plea, and the lepers'' mercy-cry of chapter 17. The crowd''s attempt to silence him mirrors the disciples'' attempt to exclude the children (v.15). Jesus stops for him, restores his sight, and the man follows him "glorifying God" (v.43) — becoming a model of the response to salvation that the rich ruler failed to make.',
  'Persistent Prayer, Humble Faith, and the Cost of Entry into the Kingdom',
  'ἐκλεκτός (eklektos)',
  'eklektos means chosen, elect, selected — those whom God has called and set apart. It appears in v.7 in the phrase "his own elect" (hoi eklektoi autou) — those who cry to him day and night. The term carries the weight of OT covenant language (Isa 42:1; 65:9; Ps 105:6) and NT election theology. In Luke 18, the elect are paradoxically those who feel most desperate — the widow with no legal power, the tax collector with no religious standing, the blind beggar with no social status. The chapter defines the elect not as the religiously accomplished but as those who cry to God in persistent, humble dependence.',
  '["The Persistent Widow: Praying and Not Fainting (vv.1-8)","The Pharisee and the Tax Collector: Humility as the Gateway to Justification (vv.9-14)","Children, the Rich Ruler, and Kingdom Entry (vv.15-30)","Third Passion Prediction and Disciples'' Incomprehension (vv.31-34)","Blind Bartimaeus: Persistent Faith and Sight Restored (vv.35-43)"]'
FROM books b WHERE b.name = 'Luke';

INSERT INTO verses (chapter_id, verse_number, kjv_text, original_text, transliteration, study_note, doctrinal_note)
SELECT c.id, v.verse_number, v.kjv_text, v.original_text, v.transliteration, v.study_note, v.doctrinal_note
FROM chapters c
JOIN books b ON c.book_id = b.id
CROSS JOIN (VALUES
  (1, 'And he spake a parable unto them to this end, that men ought always to pray, and not to faint;', 'Ἔλεγεν δὲ παραβολὴν αὐτοῖς πρὸς τὸ δεῖν πάντοτε προσεύχεσθαι αὐτοὺς καὶ μὴ ἐγκακεῖν,', 'Elegen de parabolēn autois pros to dein pantote proseuchesthai autous kai mē enkakein,', 'Luke provides an unusually explicit statement of a parable''s purpose before telling it — rare in the Synoptics. "To this end" (pros to — introducing the purpose clause). "Ought always to pray" (dein pantote proseuchesthai — it is necessary, continually, to pray; dein is the same divine necessity word used for the cross in 9:22) — persistent prayer is not optional but structurally essential to kingdom life. "Not to faint" (mē enkakein — not to grow weary, not to give up, not to become cowardly; the word has a military connotation of deserting one''s post). The parable addresses the danger of prayerlessness born of apparent divine silence.', NULL),
  (2, 'Saying, There was in a city a judge, which feared not God, neither regarded man:', 'λέγων, Κριτής τις ἦν ἔν τινι πόλει τὸν Θεὸν μὴ φοβούμενος καὶ ἄνθρωπον μὴ ἐντρεπόμενος.', 'legōn, Kritēs tis ēn en tini polei ton Theon mē phoboumenos kai anthrōpon mē entrepomenos.', '"Feared not God, neither regarded man" (ton Theon mē phoboumenos kai anthrōpon mē entrepomenos) — a double negative portrait of a judge with no vertical or horizontal accountability. "Feared not God" removes divine accountability; "neither regarded man" (mē entrepomenos — showed no shame before, was not put to shame by) removes social accountability. Such a judge is the worst possible arbiter of justice — his decisions rest entirely on personal interest. The parable''s power comes from this judge being the lowest possible baseline: if even he yields, how much more God?', NULL),
  (3, 'And there was a widow in that city; and she came unto him, saying, Avenge me of mine adversary.', 'χήρα δὲ ἦν ἐν τῇ πόλει ἐκείνῃ, καὶ ἤρχετο πρὸς αὐτὸν λέγουσα, Ἐκδίκησόν με ἀπὸ τοῦ ἀντιδίκου μου.', 'chēra de ēn en tē polei ekeinē, kai ērcheto pros auton legousa, Ekdikēson me apo tou antidikou mou.', '"A widow" (chēra) — in the ancient world, widows had no independent legal standing and no male advocate; they were the most legally vulnerable members of society (cf. Isa 1:17; Jas 1:27). "She came unto him" (ērcheto — imperfect tense: she kept coming, repeatedly coming) — her persistence is embedded in the verb tense before the parable even states it. "Avenge me" (Ekdikēson me — give me justice, vindicate me, execute the right on my behalf; ek + dikē, justice out from the situation) — a legal demand for justice from the only authority available to her.', NULL),
  (4, 'And he would not for a while: but afterward he said within himself, Though I fear not God, nor regard man;', 'καὶ οὐκ ἤθελεν ἐπὶ χρόνον· μετὰ δὲ ταῦτα εἶπεν ἐν ἑαυτῷ, Εἰ καὶ τὸν Θεὸν οὐ φοβοῦμαι καὶ ἄνθρωπον οὐκ ἐντρέπομαι,', 'kai ouk ēthelen epi chronon; meta de tauta eipen en heautō, Ei kai ton Theon ou phoboumai kai anthrōpon ouk entrepomai,', '"He would not for a while" (ouk ēthelen epi chronon — he was not willing for a time, he kept refusing) — the delay mirrors the apparent silence of God in the face of his people''s prayers. "Said within himself" (eipen en heautō — a Lucan soliloquy device, also in 12:17; 15:17; 16:3) — the reader is given privileged access to the judge''s interior reasoning. He openly acknowledges his own character: "Though I fear not God, nor regard man" — the self-description is repeated verbatim from v.2, making the judge himself agree with the narrator''s assessment.', NULL),
  (5, 'Yet because this widow troubleth me, I will avenge her, lest by her continual coming she weary me.', 'διά γε τὸ παρέχειν μοι κόπον τὴν χήραν ταύτην, ἐκδικήσω αὐτήν, ἵνα μὴ εἰς τέλος ἐρχομένη ὑπωπιάζῃ με.', 'dia ge to parechein moi kopon tēn chēran tautēn, ekdikēsō autēn, hina mē eis telos erchomenē hupōpiazē me.', '"Troubleth me" (parechein moi kopon — causing me trouble, wearing me out, giving me weariness) — the widow has become more inconvenient than ruling against her. "Lest by her continual coming she weary me" (hupōpiazē — literally: to strike under the eye, to give a black eye; figuratively: to wear out, exhaust, beat down). This vivid word is used in 1 Cor 9:27 for Paul''s bodily discipline. The judge fears being metaphorically "blackened" by the widow''s relentless petitioning — a hyperbolic image of how persistence overcomes even the most obdurate resistance.', NULL),
  (6, 'And the Lord said, Hear what the unjust judge saith.', 'Εἶπεν δὲ ὁ Κύριος, Ἀκούσατε τί ὁ κριτὴς τῆς ἀδικίας λέγει·', 'Eipen de ho Kurios, Akousate ti ho kritēs tēs adikias legei;', '"The unjust judge" (ho kritēs tēs adikias — the judge of unrighteousness, the unrighteous judge) — the genitive construction (judge of unrighteousness) is a Semitic idiom for "the thoroughly unrighteous judge," echoing the similar construction in 16:8 ("the steward of unrighteousness"). Jesus calls attention to the punch of the parable: the argument from the worst case to the best case. If the most corrupt possible judge yields to persistence, the conclusion about God follows with logical force.', NULL),
  (7, 'And shall not God avenge his own elect, which cry day and night unto him, though he bear long with them?', 'ὁ δὲ Θεὸς οὐ μὴ ποιήσῃ τὴν ἐκδίκησιν τῶν ἐκλεκτῶν αὐτοῦ τῶν βοώντων αὐτῷ ἡμέρας καὶ νυκτός, καὶ μακροθυμεῖ ἐπ'' αὐτοῖς;', 'ho de Theos ou mē poiēsē tēn ekdikēsin tōn eklektōn autou tōn boōntōn autō hēmeras kai nuktos, kai makrothumei ep'' autois?', '"His own elect" (tōn eklektōn autou — of his chosen ones) — God''s relationship to his people is not the indifferent aloofness of the unjust judge but the covenant bond of election. "Cry day and night" (boōntōn — crying out, shouting, the word used for loud distress cries; hēmeras kai nuktos — by day and by night, a merism for continuous prayer). "Though he bear long with them" (makrothumei — is long-suffering, patient; the question may mean either "though he seems slow to act" or "while he exercises patience with the enemies of the elect"). The patience of God is not indifference but purposeful restraint.', NULL),
  (8, 'I tell you that he will avenge them speedily. Nevertheless when the Son of man cometh, shall he find faith on the earth?', 'λέγω ὑμῖν ὅτι ποιήσει τὴν ἐκδίκησιν αὐτῶν ἐν τάχει. πλὴν ὁ Υἱὸς τοῦ ἀνθρώπου ἐλθὼν ἄρα εὑρήσει τὴν πίστιν ἐπὶ τῆς γῆς;', 'legō humin hoti poiēsei tēn ekdikēsin autōn en tachei. plēn ho Huios tou anthrōpou elthōn ara heurēsei tēn pistin epi tēs gēs?', '"Speedily" (en tachei — with swiftness, quickly; not meaning immediately but with the swiftness characteristic of God''s action once he moves). "Nevertheless" (plēn — but, however, the strong adversative) — a surprising pivot. The question "shall he find faith on the earth?" (heurēsei tēn pistin — will he find the faith, with definite article: that specific faith of persistent, humble crying out) introduces a note of eschatological uncertainty. The parable''s concern is not whether God will act but whether the elect will maintain the persistent, humble, dependent prayer that characterizes true faith until he does.', NULL),
  (9, 'And he spake this parable unto certain which trusted in themselves that they were righteous, and despised others:', 'Εἶπεν δὲ καὶ πρός τινας τοὺς πεποιθότας ἐφ'' ἑαυτοῖς ὅτι εἰσὶν δίκαιοι καὶ ἐξουθενοῦντας τοὺς λοιπούς, τὴν παραβολὴν ταύτην·', 'Eipen de kai pros tinas tous pepoithotas eph'' heautois hoti eisin dikaioi kai exouthenountas tous loipous, tēn parabolēn tautēn;', 'Luke again provides explicit audience identification before the parable. "Which trusted in themselves" (tous pepoithotas eph'' heautois — those who had put their confidence in themselves, perfect participle: a settled state of self-trust) "that they were righteous" (hoti eisin dikaioi — that they were righteous, dikaioi in the judicial sense of being in right standing). "Despised others" (exouthenountas — holding as nothing, treating with contempt; ex + outhen, from nothing — to count as nothing). Self-righteousness and contempt are inseparable: one''s elevation requires others'' diminishment.', NULL),
  (10, 'Two men went up into the temple to pray; the one a Pharisee, and the other a publican.', 'Ἄνθρωποι δύο ἀνέβησαν εἰς τὸ ἱερὸν προσεύξασθαι, ὁ εἷς Φαρισαῖος καὶ ὁ ἕτερος τελώνης.', 'Anthrōpoi duo anebēsan eis to hieron proseuxasthai, ho heis Pharisaios kai ho heteros telōnēs.', '"Went up" (anebēsan — ascended, as the Temple Mount required physical ascent) "into the temple to pray" — both men come for the same stated purpose. The contrast is between a Pharisee (the most religiously admired class) and a tax collector (telōnēs — the most socially despised, associated with Rome and financial corruption). The listener''s initial sympathy is entirely with the Pharisee; the parable will invert those sympathies. The parable works by refusing to confirm the audience''s prior religious categories.', NULL),
  (11, 'The Pharisee stood and prayed thus with himself, God, I thank thee, that I am not as other men are, extortioners, unjust, adulterers, or even as this publican.', 'ὁ Φαρισαῖος σταθεὶς πρὸς ἑαυτὸν ταῦτα προσηύχετο, Ὁ Θεός, εὐχαριστῶ σοί, ὅτι οὐκ εἰμὶ ὥσπερ οἱ λοιποὶ τῶν ἀνθρώπων, ἅρπαγες, ἄδικοι, μοιχοί, ἢ καὶ ὡς οὗτος ὁ τελώνης·', 'ho Pharisaios statheis pros heauton tauta prosēucheto, Ho Theos, eucharistō soi, hoti ouk eimi hōsper hoi loipoi tōn anthrōpōn, harpages, adikoi, moichoi, ē kai hōs houtos ho telōnēs;', '"Stood and prayed thus with himself" (statheis pros heauton — having stood, toward himself) — the telling phrase: the Pharisee is praying toward himself rather than toward God, despite the address. "I thank thee" (eucharistō soi) — the prayer begins with thanksgiving, a proper form, but the content reveals the problem: the thanks is for personal superiority. "Not as other men" — the prayer defines righteousness negatively through contrast. Three categories (extortioners, unjust, adulterers) and one specific comparison (this tax collector) make up the entire theological content of his prayer; God is addressed but not genuinely approached.', NULL),
  (12, 'I fast twice in the week, I give tithes of all that I possess.', 'νηστεύω δὶς τοῦ σαββάτου, ἀποδεκατῶ πάντα ὅσα κτῶμαι.', 'nēsteuō dis tou sabbatou, apodekatō panta hosa ktōmai.', '"Twice in the week" (dis tou sabbatou — twice of the Sabbath week, Mondays and Thursdays according to Jewish custom) — the Law required fasting only once a year on the Day of Atonement (Lev 16:29-31); twice-weekly fasting was a supererogatory piety. "Tithes of all that I possess" (apodekatō panta — I tithe everything I acquire; the Law required tithing of agricultural produce, not every acquisition) — again, exceeding legal requirements. The Pharisee''s prayer rehearses genuine religious achievements, which makes the parable''s verdict more striking: these achievements do not produce justification.', NULL),
  (13, 'And the publican, standing afar off, would not lift up so much as his eyes unto heaven, but smote upon his breast, saying, God be merciful to me a sinner.', 'ὁ δὲ τελώνης μακρόθεν ἑστὼς οὐκ ἤθελεν οὐδὲ τοὺς ὀφθαλμοὺς ἐπᾶραι εἰς τὸν οὐρανόν, ἀλλ'' ἔτυπτεν τὸ στῆθος αὐτοῦ λέγων, Ὁ Θεός, ἱλάσθητί μοι τῷ ἁμαρτωλῷ.', 'ho de telōnēs makrothen hestōs ouk ēthelen oude tous ophthalmous eparai eis ton ouranon, all'' etupen to stēthos autou legōn, Ho Theos, hilasthēti moi tō hamartōlō.', '"Standing afar off" (makrothen hestōs — having stood at a distance) — the posture of unworthiness, echoing the lepers of 17:12. "Would not lift up so much as his eyes unto heaven" — the refusal to assume the customary prayer posture of raised eyes (cf. Ps 123:1) expresses shame. "Smote upon his breast" (etupen to stēthos — beat his chest, the gesture of grief and self-reproach, used at the crucifixion in 23:48). "God be merciful to me a sinner" (hilasthēti moi tō hamartōlō — be propitiated to me, be graciously appeased toward me; the sinner, with the definite article, identifying himself as the sinner) — hilaskomai is the word for atonement, used in Heb 2:17. His prayer is a cry for propitiation, not performance.', NULL),
  (14, 'I tell you, this man went down to his house justified rather than the other: for every one that exalteth himself shall be humbled; and he that humbleth himself shall be exalted.', 'λέγω ὑμῖν, κατέβη οὗτος δεδικαιωμένος εἰς τὸν οἶκον αὐτοῦ παρ'' ἐκεῖνον· ὅτι πᾶς ὁ ὑψῶν ἑαυτὸν ταπεινωθήσεται, ὁ δὲ ταπεινῶν ἑαυτὸν ὑψωθήσεται.', 'legō humin, katebē houtos dedikaiōmenos eis ton oikon autou par'' ekeinon; hoti pas ho hupsōn heauton tapeinōthēsetai, ho de tapeinōn heauton hupsōthēsetai.', '"This man went down...justified" (katebē houtos dedikaiōmenos — this one descended having been declared righteous, a perfect passive participle indicating a completed forensic act). "Rather than the other" (par'' ekeinon — alongside that one, in contrast to that one) — the Pharisee descends unjustified despite his genuine religious achievements. "Justified" (dedikaiōmenos) is a forensic term from the law court: declared righteous in God''s sight, acquitted. The tax collector''s prayer was directed not at his own record but at God''s mercy; that orientation is what the doctrine of justification requires. The concluding aphorism (also in 14:11) is the interpretive key.', NULL),
  (15, 'And they brought unto him also infants, that he would touch them: but when his disciples saw it, they rebuked them.', 'Προσέφερον δὲ αὐτῷ καὶ τὰ βρέφη ἵνα αὐτῶν ἅπτηται· ἰδόντες δὲ οἱ μαθηταὶ ἐπετίμων αὐτοῖς.', 'Prosepheron de autō kai ta brephē hina autōn haptētai; idontes de hoi mathētai epetimōn autois.', '"Infants" (brephē — newborns, infants, a more specific word than paidia/children used in v.16-17) — Luke''s term emphasizes the absolute helplessness of those brought. "That he would touch them" (hina autōn haptētai — that he would touch them, lay hands on them, a gesture of blessing) — the parents desire blessing for the most vulnerable. "His disciples saw it, they rebuked them" (epetimōn — they were rebuking, imperfect: repeatedly rebuking, the same word used for rebuking storms and demons) — the disciples'' rebuke reveals their misunderstanding of kingdom priorities: the kingdom belongs precisely to those who are dependent and seemingly unproductive.', NULL),
  (16, 'But Jesus called them unto him, and said, Suffer little children to come unto me, and forbid them not: for of such is the kingdom of God.', 'ὁ δὲ Ἰησοῦς προσεκαλέσατο αὐτά, λέγων, Ἄφετε τὰ παιδία ἔρχεσθαι πρός με καὶ μὴ κωλύετε αὐτά· τῶν γὰρ τοιούτων ἐστὶν ἡ βασιλεία τοῦ Θεοῦ.', 'ho de Iēsous prosekalEsato auta, legōn, Aphete ta paidia erchesthai pros me kai mē kōluete auta; tōn gar toioutōn estin hē basileia tou Theou.', '"Called them unto him" (prosekalEsato — summoned them to himself, a deliberate counteraction to the disciples'' exclusion). "Suffer...come unto me, and forbid them not" (Aphete...kai mē kōluete — allow...and stop forbidding; two imperatives, the second being a present imperative of prohibition indicating the disciples must stop an ongoing action). "Of such is the kingdom of God" (tōn gar toioutōn estin — of such ones, of those like this, the kingdom belongs) — not because of childhood innocence (a romantic notion Luke does not teach) but because of the child''s characteristic dependence, receptivity, and inability to earn anything.', NULL),
  (17, 'Verily I say unto you, Whosoever shall not receive the kingdom of God as a little child shall in no wise enter therein.', 'ἀμὴν λέγω ὑμῖν, ὃς ἐὰν μὴ δέξηται τὴν βασιλείαν τοῦ Θεοῦ ὡς παιδίον, οὐ μὴ εἰσέλθῃ εἰς αὐτήν.', 'amēn legō humin, hos ean mē dexētai tēn basileian tou Theou hōs paidion, ou mē eiselthē eis autēn.', '"Shall in no wise enter therein" (ou mē eiselthē — the double negative, strongest possible negation in Greek) — the absolute exclusion of those who do not receive the kingdom as a child. "As a little child" (hōs paidion) — the manner of reception, not the recipient''s age. The child''s manner of receiving is the pattern: empty-handed, dependent, without negotiation or merit. The immediately following episode of the rich young ruler (vv.18-25) illustrates what the opposite of receiving as a child looks like — coming with achievements, assets, and conditions.', NULL),
  (18, 'And a certain ruler asked him, saying, Good Master, what shall I do to inherit eternal life?', 'Καὶ ἐπηρώτησέν τις αὐτὸν ἄρχων λέγων, Διδάσκαλε ἀγαθέ, τί ποιήσας ζωὴν αἰώνιον κληρονομήσω;', 'Kai epērōtēsen tis auton archōn legōn, Didaskale agathe, ti poiēsas zōēn aiōnion klēronomēsō?', '"A certain ruler" (archōn — a ruler, a person of authority; perhaps a synagogue ruler or a member of the Sanhedrin; Mark identifies him as young, Matthew identifies him as young and wealthy) — a contrast to the infants of v.15, this man comes with status and religious credentials. "Good Master" (Didaskale agathe — Good Teacher; the address is unusual, as teachers were not typically called "good" as an honorific) — the flattery is perhaps genuine. "What shall I do to inherit eternal life?" (ti poiēsas — what having done; the question frames eternal life as an achievement, the opposite of receiving as a child).', NULL),
  (19, 'And Jesus said unto him, Why callest thou me good? none is good, save one, that is, God.', 'εἶπεν δὲ αὐτῷ ὁ Ἰησοῦς, Τί με λέγεις ἀγαθόν; οὐδεὶς ἀγαθὸς εἰ μὴ εἷς ὁ Θεός.', 'eipen de autō ho Iēsous, Ti me legeis agathon? oudeis agathos ei mē heis ho Theos.', '"Why callest thou me good?" (Ti me legeis agathon — why do you call me good?) — Jesus does not reject the address but interrogates it, forcing the ruler to consider its implications. "None is good, save one, that is, God" (oudeis agathos ei mē heis ho Theos) — if "good" is a divine attribute, then calling Jesus good requires either recognizing Jesus as God or recalibrating the address. Jesus is not denying his own goodness but pressing the ruler: do you know who you are speaking to? The question is an indirect Christological claim — if goodness belongs to God alone, and you call me good, what does that make me?', NULL),
  (20, 'Thou knowest the commandments, Do not commit adultery, Do not kill, Do not steal, Do not bear false witness, Honour thy father and thy mother.', 'τὰς ἐντολὰς οἶδας, Μὴ μοιχεύσῃς, Μὴ φονεύσῃς, Μὴ κλέψῃς, Μὴ ψευδομαρτυρήσῃς, Τίμα τὸν πατέρα σου καὶ τὴν μητέρα σου.', 'tas entolas oidas, Mē moicheusēs, Mē phoneusēs, Mē klepsēs, Mē pseudomarturēsēs, Tima ton patera sou kai tēn mētera sou.', 'Jesus directs the ruler to the commandments — specifically the second table (Decalogue vv.6-10), the social commandments governing relationships with other humans. Notably, the first table (commandments concerning God) is not listed — perhaps pointing toward what will be revealed as the ruler''s actual deficiency: the idolatry of wealth (v.22). "Honour thy father and thy mother" is placed last rather than first (as in the Decalogue), perhaps because it represents the principle of giving to others what is due to them — the same principle at issue with the ruler''s possessions.', NULL),
  (21, 'And he said, All these have I kept from my youth up.', 'ὁ δὲ εἶπεν, Ταῦτα πάντα ἐφύλαξα ἐκ νεότητός μου.', 'ho de eipen, Tauta panta ephulaxa ek neotētos mou.', '"All these have I kept" (panta ephulaxa — all I have guarded, the aorist suggesting a lifetime of observance) "from my youth up" (ek neotētos — from childhood) — a remarkable claim, but not dismissible as obviously false. The man is sincere and his claim may be largely accurate at the level of external compliance. His very sincerity makes the coming diagnosis more devastating: external legal compliance, even genuine, does not touch the interior disorder of a soul whose ultimate allegiance is to its own wealth. Jesus does not contest his self-assessment; instead he reveals what the commandments have not reached.', NULL),
  (22, 'Now when Jesus heard these things, he said unto him, Yet lackest thou one thing: sell all that thou hast, and distribute unto the poor, and thou shalt have treasure in heaven: and come, follow me.', 'ἀκούσας δὲ ὁ Ἰησοῦς εἶπεν αὐτῷ, Ἔτι ἕν σοι λείπει· πάντα ὅσα ἔχεις πώλησον καὶ διάδος πτωχοῖς, καὶ ἕξεις θησαυρὸν ἐν οὐρανῷ, καὶ δεῦρο ἀκολούθει μοι.', 'akousas de ho Iēsous eipen autō, Eti hen soi leipei; panta hosa echeis pōlēson kai diadōs ptōchois, kai hexeis thēsauron en ouranō, kai deuro akolouthei moi.', '"Yet lackest thou one thing" (Eti hen soi leipei — still one thing is lacking for you) — one deficiency beneath all the compliance. "Sell all" (panta...pōlēson — sell everything; the universal scope is deliberate) — Jesus is not issuing a general command for all disciples (Zacchaeus was not required to sell all in 19:8) but a personal diagnostic: this man''s specific idol is his wealth. "Distribute unto the poor" (diadōs ptōchois — give it through [distribute] to the poor) — not one gift but a distribution. "Treasure in heaven" offers the exchange: earthly treasure for heavenly. "Come, follow me" — the invitation is to personal discipleship, the same given to the Twelve.', NULL),
  (23, 'And when he heard this, he was very sorrowful: for he was very rich.', 'ὁ δὲ ἀκούσας ταῦτα περίλυπος ἐγενήθη· ἦν γὰρ πλούσιος σφόδρα.', 'ho de akousas tauta perilupos egenēthē; ēn gar plousios sphodra.', '"Very sorrowful" (perilupos — surrounded by grief, deeply grieved; peri = around/thoroughly + lupē = grief; the same word used of Jesus in Gethsemane, Mark 14:34) — genuine emotional distress, not contempt for Jesus. "For he was very rich" (ēn gar plousios sphodra — for he was extremely wealthy) — the explanation is placed at the end for maximum emphasis. His sorrow is real; his attachment to wealth is also real. He cannot have both. The tragedy is that his grief is genuine yet insufficient to produce action; he leaves (v.23) without the invitation to follow being accepted.', NULL),
  (24, 'And when Jesus saw that he was very sorrowful, he said, How hardly shall they that have riches enter into the kingdom of God!', 'Ἰδὼν δὲ αὐτὸν ὁ Ἰησοῦς περίλυπον γενόμενον εἶπεν, Πῶς δυσκόλως οἱ τὰ χρήματα ἔχοντες εἰς τὴν βασιλείαν τοῦ Θεοῦ εἰσπορεύονται·', 'Idōn de auton ho Iēsous perilupon genomenon eipen, Pōs duskolōs hoi ta chrēmata echontes eis tēn basileian tou Theou eisporeuontai;', '"How hardly" (Pōs duskolōs — how with difficulty; duskolos means hard to please, fastidious, then difficult; a rare adverb) — the adverb is emphatic. "They that have riches" (hoi ta chrēmata echontes — those having goods, the wealthy) — Jesus makes a general statement from the specific case. The wealth itself is not the problem (Abraham was wealthy) but the idolatrous attachment to it that displaces God. When wealth becomes one''s functional security and identity, it becomes a god, and no person can serve two masters (16:13).', NULL),
  (25, 'For it is easier for a camel to go through a needle''s eye, than for a rich man to enter into the kingdom of God.', 'εὐκοπώτερον γάρ ἐστιν κάμηλον διὰ τρήματος βελόνης εἰσελθεῖν ἢ πλούσιον εἰς τὴν βασιλείαν τοῦ Θεοῦ εἰσελθεῖν.', 'eukopōteron gar estin kamēlon dia trēmatos belonēs eiselthein ē plousión eis tēn basileian tou Theou eiselthein.', '"A camel through a needle''s eye" (kamēlon dia trēmatos belonēs — camel through the hole of a needle; belonē is a sewing needle, trēma is its eye) — a humorous hyperbole, the largest common animal through the smallest common hole. The interpretive tradition that this refers to a small gate called "the Needle''s Eye" is medieval and unattested in ancient sources; the saying is a deliberate impossibility. The point is that wealth-attachment creates an impossibility for kingdom entry. The disciples'' shocked response in v.26 confirms they understood the saying literally.', NULL),
  (26, 'And they that heard it said, Who then can be saved?', 'Εἶπαν δὲ οἱ ἀκούσαντες, Καὶ τίς δύναται σωθῆναι;', 'Eipan de hoi akousantes, Kai tis dunatai sōthēnai?', '"Who then can be saved?" (Kai tis dunatai sōthēnai — and who is able to be saved?) — the disciples'' question betrays their assumption that wealth was a sign of divine favor (a common Jewish belief rooted in Deut 28 blessings). If even the wealthy cannot be saved, the disciples reason, the less wealthy have even less hope. The question is despairing: the disciples have heard a statement about rich men and extrapolated it into a statement about everyone. Jesus''s answer will not narrowly contradict them but will reframe the question entirely.', NULL),
  (27, 'And he said, The things which are impossible with men are possible with God.', 'ὁ δὲ εἶπεν, Τὰ ἀδύνατα παρὰ ἀνθρώποις δυνατὰ παρὰ τῷ Θεῷ ἐστιν.', 'ho de eipen, Ta adunata para anthrōpois dunata para tō Theō estin.', '"The things which are impossible with men" (ta adunata para anthrōpois — the impossible things beside/from the side of men) "are possible with God" (dunata para tō Theō — possible beside/from the side of God). The impossibility of the rich man''s entry is not a final verdict but a statement about human impossibility met by divine possibility. The salvation of any person — rich or poor — is impossible as a human achievement and possible only as a divine act. This is not merely comfort but a theological statement: salvation is entirely a work of God. The parable of the Pharisee and tax collector (vv.9-14) reaches the same conclusion: justification is God''s declarative act, not human accumulation.', NULL),
  (28, 'Then Peter said, Lo, we have left all, and followed thee.', 'Εἶπεν δὲ ὁ Πέτρος, Ἰδοὺ ἡμεῖς ἀφήκαμεν τὰ ἴδια καὶ ἠκολουθήσαμέν σοι.', 'Eipen de ho Petros, Idou hēmeis aphēkamen ta idia kai ēkolouthēsamen soi.', '"Lo, we have left all" (Idou hēmeis aphēkamen ta idia — Look, we have left our own things) — Peter''s statement is implicitly a question: what about us? We did what the ruler refused to do. "Ta idia" (our own things, our personal possessions) — not as comprehensive as the rich man''s wealth, but genuinely sacrificial: fishing boats, family income, homes. Peter is not boasting but asking: does our sacrifice qualify us for what the ruler forfeited? The disciples have met the external condition; Jesus will describe the internal reward.', NULL),
  (29, 'And he said unto them, Verily I say unto you, There is no man that hath left house, or parents, or brethren, or wife, or children, for the kingdom of God''s sake,', 'ὁ δὲ εἶπεν αὐτοῖς, Ἀμὴν λέγω ὑμῖν ὅτι οὐδείς ἐστιν ὃς ἀφῆκεν οἰκίαν ἢ γονεῖς ἢ ἀδελφοὺς ἢ γυναῖκα ἢ τέκνα ἕνεκεν τῆς βασιλείας τοῦ Θεοῦ,', 'ho de eipen autois, Amēn legō humin hoti oudeis estin hos aphēken oikian ē goneis ē adelphous ē gunaika ē tekna heneken tēs basileias tou Theou,', '"Amēn" — the solemn affirmation introducing a promise. The list comprehensively covers the primary attachments of life: home, parents, siblings, wife, children — all the relationships and securities that constitute a person''s world. "For the kingdom of God''s sake" (heneken tēs basileias tou Theou) — the motivation determines whether the leaving is genuine sacrifice or mere social rupture. The kingdom itself, and loyalty to Jesus its king, must be the reason for the leaving.', NULL),
  (30, 'Who shall not receive manifold more in this present time, and in the world to come life everlasting.', 'ὃς οὐχὶ μὴ ἀπολάβῃ πολλαπλασίονα ἐν τῷ καιρῷ τούτῳ, καὶ ἐν τῷ αἰῶνι τῷ ἐρχομένῳ ζωὴν αἰώνιον.', 'hos ouchi mē apolabē pollaplasiona en tō kairō toutō, kai en tō aiōni tō erchomenō zōēn aiōnion.', '"Manifold more in this present time" (pollaplasiona — many times more, manifold; en tō kairō toutō — in this season, this present age) — the reward is not deferred entirely to eternity but begins in the community of the church: new family (brothers, sisters, mothers) in the kingdom community. "In the world to come life everlasting" (en tō aiōni tō erchomenō zōēn aiōnion — in the coming age, eternal life) — the ultimate eschatological reward. The juxtaposition of present and future reward addresses the ruler''s attachment: what is left behind is not lost but multiplied in a different mode.', NULL),
  (31, 'Then he took unto him the twelve, and said unto them, Behold, we go up to Jerusalem, and all things that are written by the prophets concerning the Son of man shall be accomplished.', 'Παραλαβὼν δὲ τοὺς δώδεκα εἶπεν πρὸς αὐτούς, Ἰδοὺ ἀναβαίνομεν εἰς Ἰερουσαλήμ, καὶ τελεσθήσεται πάντα τὰ γεγραμμένα διὰ τῶν προφητῶν τῷ Υἱῷ τοῦ ἀνθρώπου·', 'Paralabōn de tous dōdeka eipen pros autous, Idou anabainomen eis Ierousalēm, kai telesthēsetai panta ta gegrammena dia tōn prophētōn tō Huiō tou anthrōpou;', '"Took unto him the twelve" (Paralabōn tous dōdeka — having taken the Twelve alongside, a private disclosure) — the passion prediction is given to the inner circle only, not to the crowds. "All things that are written by the prophets" (panta ta gegrammena dia tōn prophētōn — all the things having been written through the prophets) — the coming events are not surprises but the fulfillment of a written script. "Shall be accomplished" (telesthēsetai — will be completed, fulfilled, brought to their telos) — the divine necessity of the cross is anchored in prophetic Scripture.', NULL),
  (32, 'For he shall be delivered unto the Gentiles, and shall be mocked, and spitefully entreated, and spitted on:', 'παραδοθήσεται γὰρ τοῖς ἔθνεσιν καὶ ἐμπαιχθήσεται καὶ ὑβρισθήσεται καὶ ἐμπτυσθήσεται,', 'paradothēsetai gar tois ethnesin kai empaichthēsetai kai hubristhēsetai kai emptusthēsetai,', '"Delivered unto the Gentiles" (paradothēsetai tois ethnesin — handed over to the nations, the Gentiles) — this detail is unique to Luke in this passion prediction (cf. Isa 53:12: "poured out his soul unto death...and he was numbered with the transgressors"). "Mocked" (empaichthēsetai), "spitefully entreated" (hubristhēsetai — treated with insolent contempt, violated), "spitted on" (emptusthēsetai — spat upon) — three passive verbs of humiliation, echoing the Servant Songs. The specificity of the prediction (Gentiles, mocking, spitting, scourging, v.33) is extraordinary.', NULL),
  (33, 'And they shall scourge him, and put him to death: and the third day he shall rise again.', 'καὶ μαστιγώσαντες ἀποκτενοῦσιν αὐτόν, καὶ τῇ ἡμέρᾳ τῇ τρίτῃ ἀναστήσεται.', 'kai mastigōsantes apoktenousin auton, kai tē hēmera tē tritē anastēsetai.', '"Scourge him" (mastigōsantes — having flogged, the Roman flagellum, a brutal pre-crucifixion punishment) "put him to death" (apoktenousin — will kill him) — the passion is predicted explicitly. "The third day he shall rise again" (tē hēmera tē tritē anastēsetai — on the third day he will rise up) — the resurrection is integral to the prediction, not added as an afterthought. The disciples'' inability to understand (v.34) means the resurrection promise offers them no comfort at this point; it will only become comprehensible in resurrection light.', NULL),
  (34, 'And they understood none of these things: and this saying was hid from them, neither knew they the things which were spoken.', 'καὶ αὐτοὶ οὐδὲν τούτων συνῆκαν, καὶ ἦν τὸ ῥῆμα τοῦτο κεκρυμμένον ἀπ'' αὐτῶν, καὶ οὐκ ἐγίνωσκον τὰ λεγόμενα.', 'kai autoi ouden toutōn sunēkan, kai ēn to rhēma touto kekrummenon ap'' autōn, kai ouk eginōskon ta legomena.', 'Three increasingly emphatic statements of incomprehension: (1) "understood none of these things" (ouden toutōn sunēkan — they grasped none of it); (2) "this saying was hid from them" (kekrummenon — perfect passive participle: had been concealed, the hiding was a prior divine act, not momentary failure); (3) "neither knew they the things which were spoken" (ouk eginōskon — they kept not knowing, imperfect: continuous non-understanding). Luke''s emphasis on divine concealment (here and 9:45) prepares the resurrection narrative where the hiding is reversed: "Then opened he their understanding, that they might understand the scriptures" (24:45).', NULL),
  (35, 'And it came to pass, that as he was come nigh unto Jericho, a certain blind man sat by the way side begging:', 'Ἐγένετο δὲ ἐν τῷ ἐγγίζειν αὐτὸν εἰς Ἰεριχώ, τυφλός τις ἐκάθητο παρὰ τὴν ὁδὸν προσαιτῶν.', 'Egeneto de en tō engizein auton eis Ierichō, tuphlos tis ekathēto para tēn hodon prosaitōn.', '"As he was come nigh unto Jericho" — the journey to Jerusalem (begun in 9:51) is nearing its destination; Jericho is approximately 15 miles northeast of Jerusalem. "A certain blind man sat by the way side begging" (tuphlos tis ekathēto para tēn hodon prosaitōn — a blind certain-man was sitting beside the road begging; the participle prosaitōn — persistently begging) — like the widow and the tax collector before him, he is at the margins of society, dependent, without resources. Unlike the rich ruler who came with a question, he will come with a cry.', NULL),
  (36, 'And hearing the multitude pass by, he asked what it meant.', 'ἀκούσας δὲ ὄχλου διαπορευομένου ἐπυνθάνετο τί εἴη τοῦτο.', 'akousas de ochlou diaporeuomenou epunthaneto ti eiē touto.', '"Hearing the multitude pass by" (akousas ochlou diaporeuomenou — having heard a crowd going through) — his blindness means he must rely on his ears. "He asked what it meant" (epunthaneto ti eiē touto — he kept inquiring what this might be; the optative eiē expressing uncertainty; the imperfect epunthaneto indicating repeated asking). He cannot see what is happening; he can only ask. His inquiry will lead to the information that gives him the opportunity to cry out. The narrative pace slows to include this detail, emphasizing his active response to what he cannot see.', NULL),
  (37, 'And they told him, that Jesus of Nazareth passeth by.', 'ἀπήγγειλαν δὲ αὐτῷ ὅτι Ἰησοῦς ὁ Ναζωραῖος παρέρχεται.', 'apēngeilan de autō hoti Iēsous ho Nazōraios parerchetai.', '"Jesus of Nazareth passeth by" (Iēsous ho Nazōraios parerchetai — Jesus the Nazarene is passing by; the present tense indicating immediacy) — the information is simple, factual, and momentous. The identification "of Nazareth" is how Jesus was commonly known in the popular mind. Armed with this identification, the blind man will use a different, theologically loaded title: "Son of David" (v.38) — a messianic title that goes beyond local geographic identity to royal genealogical claim. The contrast between the crowd''s title and his own is deliberate.', NULL),
  (38, 'And he cried, saying, Jesus, thou Son of David, have mercy on me.', 'καὶ ἐβόησεν λέγων, Ἰησοῦ, υἱὲ Δαυίδ, ἐλέησόν με.', 'kai eboēsen legōn, Iēsou, huie Dauid, eleēson me.', '"Cried" (eboēsen — he shouted, bellowed; the word for a loud, urgent cry; used of the wilderness voice in 3:4) — public, unrestrained calling. "Son of David" (huie Dauid — Davidic son, the messianic title drawing on 2 Sam 7:12-16; Isa 11:1; Ps 110) — a recognition of messianic identity that exceeds the disciples'' ordinary understanding at this point. "Have mercy on me" (eleēson me — the same mercy-cry as the lepers in 17:13 and the tax collector in v.13) — not a request for information or a theological discussion but a direct, urgent plea for grace. He knows what he needs and who can provide it.', NULL),
  (39, 'And they which went before rebuked him, that he should hold his peace: but he cried so much the more, Thou Son of David, have mercy on me.', 'καὶ οἱ προάγοντες ἐπετίμων αὐτῷ ἵνα σιγήσῃ· αὐτὸς δὲ πολλῷ μᾶλλον ἔκραζεν, Υἱὲ Δαυίδ, ἐλέησόν με.', 'kai hoi proagontes epetimōn autō hina sigēsē; autos de pollō mallon ekrazen, Huie Dauid, eleēson me.', '"They which went before rebuked him" (hoi proagontes epetimōn — those going ahead were rebuking him; the imperfect: repeatedly rebuking) — the crowd''s rebuke mirrors the disciples'' rebuke of the children in v.15. In both cases, Jesus overrides the crowd''s exclusion and calls the rejected to himself. "That he should hold his peace" (hina sigēsē — that he would be silent, an aorist of finality). "But he cried so much the more" (autos de pollō mallon ekrazen — but he himself cried out all the more; pollō mallon = much more, by a great deal) — opposition intensified his persistence rather than silencing it.', NULL),
  (40, 'And Jesus stood, and commanded him to be brought unto him: and when he was come near, he asked him,', 'σταθεὶς δὲ ὁ Ἰησοῦς ἐκέλευσεν αὐτὸν ἀχθῆναι πρὸς αὐτόν· ἐγγίσαντος δὲ αὐτοῦ ἐπηρώτησεν αὐτόν,', 'statheis de ho Iēsous ekeleusen auton achthēnai pros auton; engisantos de autou epērōtēsen auton,', '"Jesus stood" (statheis — having stopped, coming to a halt) — the journey to Jerusalem pauses for one blind beggar. The entire entourage stops. "Commanded him to be brought unto him" (ekeleusen auton achthēnai pros auton — commanded him to be led to him) — the command overrides the crowd''s rejection with an authoritative summons. The same crowd that rebuked him now leads him forward. "When he was come near, he asked him" — the personal, face-to-face encounter: Jesus does not heal from a distance but draws the man close and then asks him a question.', NULL),
  (41, 'Saying, What wilt thou that I shall do unto thee? And he said, Lord, that I may receive my sight.', 'λέγων, Τί σοι θέλεις ποιήσω; ὁ δὲ εἶπεν, Κύριε, ἵνα ἀναβλέψω.', 'legōn, Ti soi theleis poiēsō? ho de eipen, Kurie, hina anablepsō.', '"What wilt thou that I shall do unto thee?" (Ti soi theleis poiēsō — what do you want me to do for you?) — the same question Jesus will ask the sons of Zebedee in Matthew (20:21), revealing his habit of drawing out an explicit articulation of need. The question dignifies the blind man: he is not a passive recipient of charity but an active participant in a personal exchange with Jesus. "That I may receive my sight" (hina anablepsō — that I may see again, the prefix ana = again suggesting he was not born blind but had lost his sight) — a simple, direct, specific request.', NULL),
  (42, 'And Jesus said unto him, Receive thy sight: thy faith hath saved thee.', 'καὶ ὁ Ἰησοῦς εἶπεν αὐτῷ, Ἀνάβλεψον· ἡ πίστις σου σέσωκέν σε.', 'kai ho Iēsous eipen autō, Anablepson; hē pistis sou sesōken se.', '"Receive thy sight" (Anablepson — see again, an aorist imperative: an immediate command) — there is no prayer, no ceremony, no spittle or touch (contrast 7:14; Mark 8:23): only the direct word of command. "Thy faith hath saved thee" (hē pistis sou sesōken se — your faith has saved you, the same formula as 7:50 and 8:48 and 17:19) — the formula that joins physical restoration to whole-person salvation. His persistent cry, his refusal to be silenced, his use of the messianic title, his specific request — all express the faith that sōzō encompasses. He receives both sight and salvation.', NULL),
  (43, 'And immediately he received his sight, and followed him, glorifying God: and all the people, when they saw it, gave praise unto God.', 'καὶ παραχρῆμα ἀνέβλεψεν, καὶ ἠκολούθει αὐτῷ δοξάζων τὸν Θεόν· καὶ πᾶς ὁ λαὸς ἰδὼν ἔδωκεν αἶνον τῷ Θεῷ.', 'kai parachrēma aneblepsen, kai ēkolouthei autō doxazōn ton Theon; kai pas ho laos idōn edōken ainon tō Theō.', '"Immediately" (parachrēma — on the spot, instantly) — the healing is instantaneous and complete. "Followed him, glorifying God" (ēkolouthei autō doxazōn ton Theon — he was following him, glorifying God; the imperfect tense suggests continuous action) — he becomes a disciple on the road to Jerusalem. His response is the opposite of the rich ruler who "went away very sorrowful" (v.23): this man, who had nothing but his cry, leaves the roadside behind and follows. "All the people...gave praise unto God" (edōken ainon — gave praise, offered a hymn of praise) — the crowd that tried to silence the cry now joins the praise.', NULL)
) AS v(verse_number, kjv_text, original_text, transliteration, study_note, doctrinal_note)
WHERE b.name = 'Luke' AND c.chapter_number = 18;
